async function loadUser(id) {
  try {
    const res = await fetch(`/api/users/${id}`);

    if (!res.ok) {
      throw new Error(`HTTP ${res.status}: Failed to load user ${id}`);
    }

    return await res.json();
  } catch (error) {
    console.error('loadUser failed:', error.message);
    // Return null or a fallback so callers can handle gracefully
    return null;
  }
}

async function loadDashboard(userId) {
  const [ordersResult, profileResult, notificationsResult] = await Promise.allSettled([
    fetch(`/api/users/${userId}/orders`).then(r => r.json()),
    fetch(`/api/users/${userId}/profile`).then(r => r.json()),
    fetch(`/api/users/${userId}/notifications`).then(r => r.json()),
  ]);

  return {
    orders:        ordersResult.status === 'fulfilled' ? ordersResult.value : [],
    profile:       profileResult.status === 'fulfilled' ? profileResult.value : null,
    notifications: notificationsResult.status === 'fulfilled' ? notificationsResult.value : [],
  };
}

class ApiError extends Error {
  constructor(message, status) {
    super(message);
    this.name = 'ApiError';
    this.status = status;
  }
}

async function apiFetch(url) {
  const res = await fetch(url);

  if (res.status === 401) throw new ApiError('Unauthorized', 401);
  if (res.status === 404) throw new ApiError('Not found', 404);
  if (!res.ok)            throw new ApiError(`Server error`, res.status);

  return res.json();
}

// Caller can now branch on error type
try {
  const user = await apiFetch('/api/me');
} catch (err) {
  if (err instanceof ApiError && err.status === 401) {
    redirectToLogin();
  } else {
    showGenericError(err.message);
  }
}

// Browser
window.addEventListener('unhandledrejection', (event) => {
  console.error('Unhandled promise rejection:', event.reason);
  // Send to your error tracker
  Sentry.captureException(event.reason);
});

// Node.js
process.on('unhandledRejection', (reason, promise) => {
  console.error('Unhandled Rejection at:', promise, 'reason:', reason);
  process.exit(1); // fail loudly in production
});
